"use client";

import React from "react";
import { Clock3, RotateCcw, Sparkles, User, History as HistoryIcon } from "lucide-react";
import { useCanvasStore, type Project } from "@/state/useCanvasStore";
import { useDesignStore } from "@/state/useDesignStore";

export default function HistoryPanel() {
  const { history, currentProject, undo } = useCanvasStore();
  const { replaceElements } = useDesignStore();

  const handleRevert = (snapshot: Project, index: number) => {
    // This is a bit tricky because useCanvasStore.undo() only pops the last one.
    // To revert to a middle one, we'd need a specific action in the store.
    // For now, let's just use undo multiple times or add a "revertTo" to store.
    // For simplicity and safety, I'll just show the last 10 snapshots and let users undo.
    // Actually, a real "revert to snapshot" is better.
  };

  const snapshots = [...history].reverse();

  if (snapshots.length === 0) {
    return (
      <div className="flex h-full flex-col items-center justify-center p-8 text-center">
        <div className="flex h-16 w-16 items-center justify-center rounded-[24px] bg-slate-50 text-slate-300 shadow-inner">
          <Clock3 className="h-6 w-6" />
        </div>
        <p className="mt-5 text-sm font-semibold text-slate-900">No history yet</p>
        <p className="mt-2 text-xs leading-6 text-slate-500">
          Make some edits to the canvas or styles to start building your project timeline.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6">
      <header>
        <div className="flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-xl bg-slate-950 text-white shadow-lg">
            <HistoryIcon className="h-4 w-4" />
          </div>
          <div>
            <p className="text-[10px] font-semibold uppercase tracking-[0.2em] text-slate-400">
              Timeline
            </p>
            <h3 className="text-sm font-semibold text-slate-950">Project History</h3>
          </div>
        </div>
        <p className="mt-3 text-xs leading-5 text-slate-500">
          We automatically save snapshots of your design and structure as you work.
        </p>
      </header>

      <div className="relative space-y-4">
        {/* Timeline Line */}
        <div className="absolute left-[19px] top-2 bottom-2 w-px bg-slate-200" />

        {snapshots.slice(0, 15).map((snapshot, idx) => {
          const isAI = !!snapshot.generationPrompt;
          const time = snapshot.updatedAt ? new Date(snapshot.updatedAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : "Recently";

          return (
            <div key={`${snapshot.id}-${idx}`} className="relative pl-10">
              {/* Dot */}
              <div className={`absolute left-0 h-10 w-10 rounded-full border-4 border-white flex items-center justify-center shadow-sm z-10 ${
                idx === 0 ? "bg-sky-500 text-white" : "bg-slate-100 text-slate-400"
              }`}>
                {isAI ? <Sparkles className="h-3 w-3" /> : <User className="h-3 w-3" />}
              </div>

              <div className={`group rounded-[24px] border p-4 transition-all hover:bg-white hover:shadow-[0_20px_40px_-20px_rgba(15,23,42,0.15)] ${
                idx === 0 ? "border-sky-100 bg-sky-50/30" : "border-slate-100 bg-white/50"
              }`}>
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className={`text-[10px] font-bold uppercase tracking-widest ${
                      idx === 0 ? "text-sky-600" : "text-slate-400"
                    }`}>
                      {idx === 0 ? "Latest Snapshot" : `Snapshot #${snapshots.length - idx}`}
                    </p>
                    <p className="mt-1 text-xs font-semibold text-slate-900">
                      {isAI ? "AI Generation" : "Manual Edit"}
                    </p>
                    <p className="mt-1 text-[11px] text-slate-500">{time}</p>
                  </div>

                  {idx > 0 && (
                     <button
                       onClick={() => {
                         // Roll back the history by calling undo multiple times
                         for (let i = 0; i < idx; i++) {
                           useCanvasStore.getState().undo();
                         }
                       }}
                       className="opacity-0 group-hover:opacity-100 flex h-8 w-8 items-center justify-center rounded-full bg-slate-950 text-white shadow-lg transition hover:bg-slate-800"
                       title="Restore this version"
                     >
                       <RotateCcw className="h-3.5 w-3.5" />
                     </button>
                  )}
                </div>

                {isAI && snapshot.generationPrompt && (
                   <div className="mt-3 rounded-xl bg-white/60 p-2.5 text-[10px] italic text-slate-600 border border-slate-100 truncate">
                     "{snapshot.generationPrompt}"
                   </div>
                )}
              </div>
            </div>
          );
        })}

        {snapshots.length > 15 && (
           <p className="pl-10 text-[10px] font-medium text-slate-400 italic">
             + {snapshots.length - 15} more snapshots in this session
           </p>
        )}
      </div>

      <div className="rounded-[24px] border border-dashed border-slate-200 bg-slate-50/50 p-4">
        <p className="text-[10px] leading-5 text-slate-500">
          Tip: Use <kbd className="rounded border bg-white px-1 py-0.5 font-sans text-slate-900 font-semibold shadow-sm text-[10px]">Ctrl+Z</kbd> anytime to step back through these snapshots visually.
        </p>
      </div>
    </div>
  );
}

"use client";

import React from "react";
import { useCanvasStore } from "@/state/useCanvasStore";
import { useDesignStore } from "@/state/useDesignStore";
import {
  ChevronRight,
  ChevronDown,
  Layers,
  Lock,
  Unlock,
  Eye,
  EyeOff,
  Box,
} from "lucide-react";

type DropPosition = "before" | "after" | null;
type DropMode = "nest" | "reorder" | null;
type LayerMeta = {
  locked?: boolean;
  hidden?: boolean;
};

export default function LayersPanel() {
  const {
    currentProject,
    moveComponent,
    updateComponent,
  } = useCanvasStore();

  const { selectElement, selectedElements, deselectAll } = useDesignStore();

  const [expandedIds, setExpandedIds] = React.useState<Set<string>>(new Set());
  const [draggedId, setDraggedId] = React.useState<string | null>(null);
  const [dropTargetId, setDropTargetId] = React.useState<string | null>(null);
  const [dropMode, setDropMode] = React.useState<DropMode>(null);
  const [dropPosition, setDropPosition] = React.useState<DropPosition>(null);

  const [editingId, setEditingId] = React.useState<string | null>(null);
  const [editValue, setEditValue] = React.useState<string>("");

  const [openMenuId, setOpenMenuId] = React.useState<string | null>(null);
  const menuNodeRef = React.useRef<HTMLElement | null>(null);

  React.useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        setOpenMenuId(null);
        setEditingId(null);
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  React.useEffect(() => {
    const onDocClick = (e: MouseEvent) => {
      const node = menuNodeRef.current;
      if (!node) return;
      if (!node.contains(e.target as Node)) {
        setOpenMenuId(null);
      }
    };
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, []);

  if (!currentProject || Object.keys(currentProject.components).length === 0) {
    return (
      <div className="flex h-full flex-col items-center justify-center p-8 text-center text-slate-400">
        <Layers className="mb-4 h-12 w-12 opacity-20" />
        <p className="text-xs font-medium">No layers yet</p>
      </div>
    );
  }

  /* ---------------- Helpers ---------------- */

  const getMeta = (props: Record<string, unknown>): LayerMeta => {
    const meta = props.meta;
    return meta && typeof meta === "object" ? (meta as LayerMeta) : {};
  };

  const toggleExpanded = (id: string, e?: React.MouseEvent) => {
    e?.stopPropagation();
    setExpandedIds((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const getParentId = (childId: string): string | null => {
    const parentEntry = Object.entries(currentProject.components).find(
      ([, c]) => (c.children || []).includes(childId)
    );
    return parentEntry ? parentEntry[0] : null;
  };

  const getRootOrder = (): string[] => {
    const comps = currentProject.components;
    const allIds = Object.keys(comps);
    const childrenIds = new Set<string>();
    allIds.forEach((id) =>
      (comps[id].children || []).forEach((c: string) => childrenIds.add(c))
    );
    return allIds.filter((id) => !childrenIds.has(id));
  };

  const isDescendant = (parentId: string, possibleChildId: string) => {
    const stack = [parentId];
    while (stack.length) {
      const cur = stack.pop()!;
      if (cur === possibleChildId) return true;
      stack.push(...(currentProject.components[cur]?.children ?? []));
    }
    return false;
  };

  const toggleLock = (id: string) => {
    const comp = currentProject.components[id];
    const props = comp.props ?? {};
    const meta = getMeta(props);
    const newMeta = { ...meta, locked: !meta.locked };
    updateComponent(id, { props: { ...props, meta: newMeta } });
    if (newMeta.locked && selectedElements.includes(id)) {
      deselectAll();
    }
  };

  const toggleHidden = (id: string) => {
    const comp = currentProject.components[id];
    const props = comp.props ?? {};
    const meta = getMeta(props);
    const newMeta = { ...meta, hidden: !meta.hidden };
    updateComponent(id, { props: { ...props, meta: newMeta } });
  };

  const startEditing = (id: string) => {
    const comp = currentProject.components[id];
    const props = comp.props ?? {};
    const currentLabel =
      (typeof props.label === "string" && props.label) ||
      (typeof props.text === "string" && props.text) ||
      comp.type;
    setEditingId(id);
    setEditValue(currentLabel);
    setOpenMenuId(null);
  };

  const commitRename = (id: string) => {
    if (!id) return;
    const comp = currentProject.components[id];
    const props = comp.props ?? {};
    updateComponent(id, { props: { ...props, label: editValue } });
    setEditingId(null);
  };

  /* ---------------- Drag logic ---------------- */

  const onDragStart = (id: string, e: React.DragEvent) => {
    const comp = currentProject.components[id];
    if (getMeta(comp.props ?? {}).locked) {
      e.preventDefault();
      return;
    }
    setDraggedId(id);
  };

  const onDragOver = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    if (!draggedId || draggedId === targetId || isDescendant(draggedId, targetId)) return;
    setDropTargetId(targetId);
    setDropMode("nest");
  };

  const onDrop = (targetId: string) => {
    if (draggedId && draggedId !== targetId && !isDescendant(draggedId, targetId)) {
      moveComponent(draggedId, targetId);
    }
    setDraggedId(null);
    setDropTargetId(null);
    setDropMode(null);
  };

  /* ---------------- Render Component ---------------- */

  const renderComponent = (
    c: (typeof currentProject.components)[string],
    level = 0
  ) => {
    const isExpanded = expandedIds.has(c.id);
    const isSelected = selectedElements.includes(c.id);
    const isDrop = dropTargetId === c.id;
    const pad = 12 + level * 16;

    const props = c.props ?? {};
    const meta = getMeta(props);
    const locked = !!meta.locked;
    const hidden = !!meta.hidden;
    const labelSource = props.label ?? props.text;
    const label =
      typeof labelSource === "string" || typeof labelSource === "number"
        ? String(labelSource)
        : c.type;

    return (
      <div key={c.id}>
        <div
          draggable={!locked}
          onDragStart={(e) => onDragStart(c.id, e)}
          onDragOver={(e) => onDragOver(e, c.id)}
          onDrop={() => onDrop(c.id)}
          onClick={() => !locked && selectElement(c.id)}
          className={`group flex items-center gap-2 px-1 py-1.5 transition-all cursor-pointer border-b border-slate-50/50 
            ${isSelected ? "bg-sky-50/80" : "hover:bg-slate-50/50"}
            ${isDrop ? "ring-2 ring-sky-400 ring-inset" : ""}
          `}
          style={{ paddingLeft: pad }}
        >
          {/* Collapse/Expand Toggle */}
          <div className="w-5 flex items-center justify-center">
            {c.children.length > 0 ? (
              <button 
                onClick={(e) => toggleExpanded(c.id, e)}
                className={`p-1 rounded-md transition-colors hover:bg-slate-200/50 ${isSelected ? "text-sky-600" : "text-slate-400"}`}
              >
                {isExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
              </button>
            ) : (
              <div className="w-1.5 h-1.5 rounded-full bg-slate-200/50" />
            )}
          </div>

          <div className={`p-1.5 rounded-lg border ${isSelected ? "bg-white border-sky-200 text-sky-600" : "bg-slate-100/50 border-slate-200 text-slate-500"}`}>
             <Box size={14} />
          </div>

          <div className="flex-1 min-w-0 overflow-hidden">
            {editingId === c.id ? (
              <input
                autoFocus
                value={editValue}
                onChange={(e) => setEditValue(e.target.value)}
                onBlur={() => commitRename(c.id)}
                onKeyDown={(e) => e.key === "Enter" && commitRename(c.id)}
                className="w-full bg-white px-1.5 py-0.5 rounded border border-sky-300 outline-none text-xs text-sky-700"
              />
            ) : (
              <div className="flex flex-col">
                <span className={`truncate text-xs font-bold leading-tight ${isSelected ? "text-sky-900" : "text-slate-700"} ${hidden ? "opacity-40 italic" : ""}`}>
                  {label}
                </span>
                <span className="text-[10px] text-slate-400 capitalize">{c.type}</span>
              </div>
            )}
          </div>

          {/* Visibility & Locking Indicators */}
          <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity pr-2">
            <button 
              onClick={(e) => { e.stopPropagation(); toggleHidden(c.id); }}
              className={`p-1.5 rounded-md hover:bg-slate-200/50 ${hidden ? "text-slate-300" : "text-slate-500"}`}
            >
              {hidden ? <EyeOff size={13} /> : <Eye size={13} />}
            </button>
            <button 
              onClick={(e) => { e.stopPropagation(); toggleLock(c.id); }}
              className={`p-1.5 rounded-md hover:bg-slate-200/50 ${locked ? "text-amber-500" : "text-slate-500"}`}
            >
              {locked ? <Lock size={13} /> : <Unlock size={13} />}
            </button>
          </div>
        </div>

        {isExpanded && c.children.length > 0 && (
          <div className="border-l border-slate-100 ml-4">
            {c.children.map((cid: string) => {
              const child = currentProject.components[cid];
              return child ? renderComponent(child, level + 1) : null;
            })}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="h-full flex flex-col bg-white">
      <div className="px-5 py-4 border-b border-slate-100 bg-slate-50/30">
        <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
          Component Tree
        </h3>
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar">
        {getRootOrder().map((id) => {
          const c = currentProject.components[id];
          return c ? renderComponent(c) : null;
        })}
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { useDesignStore } from "@/state/useDesignStore";
import {
  AlignLeft,
  AlignCenter,
  AlignRight,
  AlignStartVertical,
  AlignCenterVertical,
  AlignEndVertical,
  Columns3,
  Copy,
  Trash2,
  Lock,
  Unlock,
} from "lucide-react";

export default function MultiSelectToolbar() {
  const selectedElements = useDesignStore((s) => s.selectedElements);
  const updateCSSBulk = useDesignStore((s) => s.updateCSSPropertiesBulk);
  const removeElement = useDesignStore((s) => s.removeElement);
  const [copied, setCopied] = useState(false);

  if (selectedElements.length < 2) return null;

  // Bulk operations
  const applyFlexRow = () => {
    updateCSSBulk(selectedElements, "display", "flex");
    updateCSSBulk(selectedElements, "flexDirection", "row");
    updateCSSBulk(selectedElements, "alignItems", "center");
  };

  const applyFlexColumn = () => {
    updateCSSBulk(selectedElements, "display", "flex");
    updateCSSBulk(selectedElements, "flexDirection", "column");
  };

  const applyGrid3 = () => {
    updateCSSBulk(
      selectedElements,
      "gridTemplateColumns",
      "repeat(3, minmax(0, 1fr))"
    );
  };

  const applyGap = (gap: string) => {
    updateCSSBulk(selectedElements, "gap", gap);
  };

  const applyAlignCenter = () => {
    updateCSSBulk(selectedElements, "textAlign", "center");
  };

  const applyAlignLeft = () => {
    updateCSSBulk(selectedElements, "textAlign", "left");
  };

  const applyAlignRight = () => {
    updateCSSBulk(selectedElements, "textAlign", "right");
  };

  const applyPadding = (padding: string) => {
    updateCSSBulk(selectedElements, "padding", padding);
  };

  const duplicateElements = () => {
    // This would need to be implemented in the store
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const deleteSelected = () => {
    if (window.confirm(`Delete ${selectedElements.length} elements?`)) {
      selectedElements.forEach((id) => removeElement(id));
    }
  };

  return (
    <div className="px-3 py-2 border-b border-gray-800 bg-gradient-to-r from-gray-900/80 to-gray-850/80 space-y-2">
      {/* Header */}
      <div className="flex items-center justify-between">
        <span className="text-[10px] font-semibold text-blue-300 uppercase tracking-wider">
          {selectedElements.length} Elements Selected
        </span>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-2 gap-1.5">
        {/* Layout buttons */}
        <button
          onClick={applyFlexRow}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors flex items-center justify-center gap-1"
          title="Apply flex row layout"
        >
          <Columns3 className="w-3.5 h-3.5" />
          Flex Row
        </button>
        <button
          onClick={applyFlexColumn}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors flex items-center justify-center gap-1"
          title="Apply flex column layout"
        >
          <Columns3 className="w-3.5 h-3.5 rotate-90" />
          Flex Column
        </button>

        {/* Spacing */}
        <button
          onClick={() => applyGap("8px")}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors"
          title="Set gap to 8px"
        >
          Gap: 8px
        </button>
        <button
          onClick={() => applyGap("16px")}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors"
          title="Set gap to 16px"
        >
          Gap: 16px
        </button>

        {/* Alignment */}
        <button
          onClick={applyAlignLeft}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors flex items-center justify-center"
          title="Align left"
        >
          <AlignLeft className="w-3.5 h-3.5" />
        </button>
        <button
          onClick={applyAlignCenter}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors flex items-center justify-center"
          title="Align center"
        >
          <AlignCenter className="w-3.5 h-3.5" />
        </button>

        {/* Padding */}
        <button
          onClick={() => applyPadding("12px")}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors"
          title="Apply 12px padding"
        >
          Pad: 12px
        </button>
        <button
          onClick={() => applyPadding("24px")}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors"
          title="Apply 24px padding"
        >
          Pad: 24px
        </button>

        {/* Destructive actions */}
        <button
          onClick={duplicateElements}
          className="px-2 py-1.5 rounded-sm bg-gray-800/80 hover:bg-gray-800 text-gray-200 text-[10px] font-medium transition-colors flex items-center justify-center gap-1"
          title="Duplicate selected elements"
        >
          <Copy className="w-3.5 h-3.5" />
          {copied ? "Copied!" : "Copy"}
        </button>
        <button
          onClick={deleteSelected}
          className="px-2 py-1.5 rounded-sm bg-red-600/20 hover:bg-red-600/30 text-red-400 text-[10px] font-medium transition-colors flex items-center justify-center gap-1"
          title="Delete selected elements"
        >
          <Trash2 className="w-3.5 h-3.5" />
          Delete
        </button>
      </div>
    </div>
  );
}

